import os
from pathlib import Path

# Search for .env files in common locations
search_paths = [
    Path.home() / ".hermes",
    Path.home(),
    Path.cwd(),
]

for search_path in search_paths:
    if search_path.exists():
        env_files = list(search_path.glob("**/.env*"))
        print(f"{search_path}:")
        for f in env_files:
            print(f"  {f}")

# Check for HERMES env vars
print(f"\nHERMES_HOME: {os.environ.get('HERMES_HOME', 'not set')}")

# List MCP config
mcp_config = Path("./config/mcporter.json")
if mcp_config.exists():
    import json
    config = json.loads(mcp_config.read_text())
    print(f"\nMCP config found: {mcp_config}")
    print(json.dumps(config, indent=2))
else:
    print(f"\nMCP config not found at {mcp_config}")

# List any mcp.json or similar
for p in search_paths:
    if p.exists():
        for f in p.glob("**/*mcp*"):
            print(f"Found MCP-related: {f}")
